#!/usr/bin/env python3\n\"\"\"\nSubscription System Test Script\n==============================\n\nThis script tests the subscription system functionality without running the full server.\n\"\"\"\n\nimport os\nimport sys\nfrom datetime import datetime, timezone\n\n# Add the backend directory to Python path\nsys.path.insert(0, os.path.dirname(os.path.abspath(__file__)))\n\nfrom app import create_app\nfrom app.extensions import db\nfrom app.models import User, Plan, Subscription\nfrom app.subscription.service import SubscriptionService\n\ndef test_subscription_system():\n    \"\"\"Test subscription system functionality\"\"\"\n    app = create_app()\n    \n    with app.app_context():\n        print(\"🧪 Testing OTPGuard Subscription System...\\n\")\n        \n        # Test 1: Check plans exist\n        print(\"1️⃣ Testing Plans:\")\n        plans = Plan.query.all()\n        for plan in plans:\n            print(f\"   ✅ {plan.display_name} - {plan.price_kes/100:.0f} KES\")\n            print(f\"      Max Users: {plan.max_users if plan.max_users != -1 else 'Unlimited'}\")\n            print(f\"      Channels: {', '.join(plan.otp_channels)}\")\n            print(f\"      Features: {', '.join(plan.features)}\")\n            print()\n        \n        # Test 2: Check user subscriptions\n        print(\"2️⃣ Testing User Subscriptions:\")\n        users = User.query.all()\n        for user in users:\n            subscription = user.current_subscription\n            if subscription:\n                status = \"🟢 Active\" if subscription.is_active else \"🔴 Inactive\"\n                trial = \" (Trial)\" if subscription.is_trial else \"\"\n                print(f\"   {status} {user.email} -> {subscription.plan.display_name}{trial}\")\n            else:\n                print(f\"   ❌ {user.email} -> No subscription\")\n        print()\n        \n        # Test 3: Test plan features\n        print(\"3️⃣ Testing Plan Features:\")\n        test_user = users[0] if users else None\n        if test_user:\n            print(f\"   Testing with user: {test_user.email}\")\n            \n            # Test channel access\n            channels = ['email', 'sms', 'totp']\n            for channel in channels:\n                can_use = test_user.can_use_channel(channel)\n                status = \"✅\" if can_use else \"❌\"\n                print(f\"   {status} {channel.upper()} channel\")\n            \n            # Test feature access\n            features = ['basic_dashboard', 'full_dashboard', 'admin_dashboard', 'custom_branding']\n            for feature in features:\n                has_feature = test_user.has_feature(feature)\n                status = \"✅\" if has_feature else \"❌\"\n                print(f\"   {status} {feature}\")\n            \n            # Test user limits\n            user_count = test_user.get_user_count()\n            plan = test_user.current_plan\n            if plan:\n                limit = plan.max_users if plan.max_users != -1 else \"Unlimited\"\n                print(f\"   📊 Current users: {user_count} / {limit}\")\n        print()\n        \n        # Test 4: Test subscription service methods\n        print(\"4️⃣ Testing Subscription Service:\")\n        if test_user:\n            # Test user limit check\n            allowed, message = SubscriptionService.check_user_limit(test_user.id)\n            status = \"✅\" if allowed else \"❌\"\n            print(f\"   {status} User limit check: {message}\")\n            \n            # Test channel check\n            allowed, message = SubscriptionService.check_otp_channel(test_user.id, 'sms')\n            status = \"✅\" if allowed else \"❌\"\n            print(f\"   {status} SMS channel check: {message}\")\n            \n            # Test feature check\n            allowed, message = SubscriptionService.check_feature_access(test_user.id, 'admin_dashboard')\n            status = \"✅\" if allowed else \"❌\"\n            print(f\"   {status} Admin dashboard feature: {message}\")\n            \n            # Test SMS cost calculation\n            cost = SubscriptionService.calculate_sms_cost(test_user.id)\n            print(f\"   💰 SMS cost: {cost:.2f} KES per message\")\n        print()\n        \n        # Test 5: Test usage logging\n        print(\"5️⃣ Testing Usage Logging:\")\n        if test_user:\n            # Log some test usage\n            SubscriptionService.log_usage(\n                user_id=test_user.id,\n                usage_type='email_otp',\n                quantity=1,\n                extra_data={'email': test_user.email, 'test': True}\n            )\n            \n            SubscriptionService.log_usage(\n                user_id=test_user.id,\n                usage_type='sms_otp',\n                quantity=1,\n                cost_kes=3.0,\n                extra_data={'phone': '+254700000000', 'test': True}\n            )\n            \n            # Get usage stats\n            stats = SubscriptionService.get_usage_stats(test_user.id)\n            print(f\"   📊 Monthly usage stats:\")\n            print(f\"      Email OTPs: {stats['email_otp_count']}\")\n            print(f\"      SMS OTPs: {stats['sms_otp_count']}\")\n            print(f\"      Total cost: {stats['total_cost_kes']:.2f} KES\")\n        print()\n        \n        print(\"🎉 All tests completed successfully!\")\n        print(\"\\n📋 Summary:\")\n        print(f\"   • {len(plans)} subscription plans configured\")\n        print(f\"   • {len([u for u in users if u.current_subscription])} users with active subscriptions\")\n        print(f\"   • Feature enforcement working\")\n        print(f\"   • Usage tracking functional\")\n        print(f\"   • Ready for M-Pesa integration\")\n\nif __name__ == '__main__':\n    test_subscription_system()